scwin.onUdcCompleted = function () {
  scwin.f_setDefaultCondition();
  $c.gus.cfEnableBtnOnly($p, [btn_Create]);
  $c.gus.cfDisableBtnOnly($p, [btn_Modify, btn_Save, btn_Cancel, pu_image]);
  scwin.f_DisableData();

  // 동원로엑스 - HR팀, 재경팀은 모든 귀속부서 조회가능
  // 넥스트로 - 기획관리팀(넥스트로) 모든 귀속부서 조회가능
  if (scwin.vAcctDeptCd == "00006" || scwin.vAcctDeptCd == "00009" || scwin.vAcctDeptCd == "01387") {
    $c.gus.cfEnableObjects($p, [ed_acctDeptCd_param, ed_acctDeptNm_param, img_PopUp2]);
    ed_acctDeptCd_param.focus();
  } else {
    $c.gus.cfDisableObjects($p, [ed_acctDeptCd_param, ed_acctDeptNm_param, img_PopUp2]);
  }
  scwin.f_setCompanyInfo();
};

