// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  let param = "";
  switch (disGubun) {
    // 조회 조건
    case 1:
      // 부서
      param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",";
      udc_acctDeptCd_param.setSelectId("retrieveAcctDeptCdInfo6");
      udc_acctDeptCd_param.cfCommonPopUp(scwin.udc_acctDeptCd_param_cb, pCode, pName, pClose, null, null, null, null, param, null, null, null, null); // 부서

      break;
    case 2:
      //성명
      param = "," + ed_coCd.getValue();
      udc_staffNo_param.setSelectId("retrieveStaffListForDayLaborers");
      udc_staffNo_param.cfCommonPopUp(scwin.udc_staffNo_param_cb, pCode, pName, pClose, null, null, null, null, param, null, null, null, null); //직급

      break;

    // 상세출력창
    case 11:
      // 부서
      param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0";
      udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
      udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_cb, pCode, pName, pClose, null, null, null, null, param, null, null, null, null); //상세출력창 

      break;
    case 22:
      //상세직종
      if (lc_occptypeCd.getValue() == "") {
        $c.win.alert($p, "직종을 먼저 선택하십시오.");
        lc_occptypeCd.focus();
        return;
      }
      param = lc_occptypeCd.getValue();
      udc_dtlOccptypeCd.setSelectId("retrieveDtlOccptype");
      udc_dtlOccptypeCd.cfCommonPopUp(scwin.udc_dtlOccptypeCd_cb, pCode, pName, pClose, null, null, null, null, param, null, null, null, null); //직급

      break;
    case 33:
      //직급
      udc_occpgrdCd.setSelectId("retrieveOccpgrd");
      udc_occpgrdCd.cfCommonPopUp(scwin.udc_occpgrdCd_cb, pCode, pName, pClose, null, null, null, null, null, null, null, null, null); //직급

      break;
    case 44:
      // 거래처
      param = ed_coCd.getValue();
      udc_mgntClntNo.setSelectId("retrieveClntEmpNoList");
      udc_mgntClntNo.cfCommonPopUp(scwin.udc_mgntClntNo_cb, pCode, pName, pClose, null, null, null, null, param, null, null, null, null);
      break;
    case 55:
      // 우편번호
      //popupResult  = window.showModalDialog("/cm/zz/newzipcodePopup.jsp", "", "dialogHeight:400px;dialogWidth:530px;center:yes;scroll:no;status:no;help:no"); // 우편번호
      // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
      //if (popupResult != null) {
      //ed_zip.Text = popupResult.zip;
      //txt_addr1.value = popupResult.addr1;
      //}
      let data = {};
      let popupResult;
      const options = {
        id: "newzipcodePopup",
        type: "popup",
        modal: true,
        popupName: "우편번호",
        width: 530,
        height: 400
      };
      popupResult = await $c.win.openPopup($p, "/ui/cm/zz/newzipcodePopup.xml", options, data);
      if (popupResult != null) {
        ed_zip.setValue(popupResult.zip);
        ed_addr1.setValue(popupResult.addr1);
        ed_addr2.focus();
      } else {
        ed_zip.setValue("");
        ed_addr1.setValue("");
        ed_addr2.setValue("");
        ed_zip.focus();
      }
      break;
    default:
      return;
  }
};

