scwin.f_Update = function () {
  // 수정버튼 클리시 수정/신규 버튼은 비활성화 되고, 저장, 취소 버튼은 활성화 된다. 
  $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, pu_image]);
  $c.gus.cfDisableBtnOnly($p, [btn_Create, btn_Modify]);

  // 수정 버튼 클릭시 하단 상세 정보 출력창 전부 활성화
  scwin.f_EnableData();
  lc_payGbn.setValue(lc_payGbn.getValue());
};

//<!-- 조회 TR-->
scwin.sbm_retrieve_submiterror = function (e) {
  //cfShowError(tr_retrieve);
  $c.gus.cfAlertMsg($p, e.responseJSON.resultDataSet[1].Msg);
  if (ds_out.getRowCount() > 0) {
    $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Modify]);
    $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel, pu_image]);
  } else {
    $c.gus.cfDisableBtnOnly($p, [btn_Modify]);
  }
};
scwin.sbm_retrieve_submitdone = function (e) {
  if (ds_out.getRowCount() > 0) {
    $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Modify]);
    $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel, pu_image]);
    ds_out.setRowPosition(0);
    gr_out.setFocusedCell(0, 0, false);
  } else {
    $c.gus.cfDisableBtnOnly($p, [btn_Modify]);
  }
  $c.gus.cfDisableObjects($p, [ed_dayPayAmt, ed_timePayAmt, ed_payAmt]);
  if (ds_out.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
  }
  ed_totalRows.setValue(ds_out.getRowCount());
};

//<!-- 저장 TR -->
scwin.sbm_save_submitdone = function (e) {
  $c.gus.cfAlertMsg($p, MSG_CM_INF_001);

  // 저장버튼 클리시 수정/신규 버튼은 활성화 되고, 저장, 취소 버튼은 비활성화 된다.
  $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Modify]);
  $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel, pu_image]);
  scwin.f_Retrieve();
};
