//급여구분
scwin.lc_payGbn_onchange = function (info) {
  if (lc_payGbn.getValue() == "01") {
    //월급
    ed_dayPayAmt.setValue(0);
    ed_timePayAmt.setValue(0);
    $c.gus.cfDisableObjects($p, [ed_dayPayAmt, ed_timePayAmt]);
    $c.gus.cfEnableObjects($p, [ed_payAmt]);
  } else if (lc_payGbn.getValue() == "02") {
    //일당제
    ed_payAmt.setValue(0);
    ed_timePayAmt.setValue(0);
    $c.gus.cfDisableObjects($p, [ed_payAmt, ed_timePayAmt]);
    $c.gus.cfEnableObjects($p, [ed_dayPayAmt]);
  } else {
    //시급
    ed_payAmt.setValue(0);
    ed_dayPayAmt.setValue(0);
    $c.gus.cfDisableObjects($p, [ed_payAmt, ed_dayPayAmt]);
    $c.gus.cfEnableObjects($p, [ed_timePayAmt]);
  }
};
